// Package registry defines the shared inputs and factory type for tool modules
// and assembles the enabled module set from an explicit factory slice. The
// aggregator (internal/mcpserver, generated by tools/genmodules) supplies that
// slice, so module wiring is explicit rather than hidden in init-time global
// state.
package registry

import (
	"log/slog"

	"github.com/crowdstrike/gofalcon/falcon/client"

	"github.com/crowdstrike/falcon-mcp/internal/modules/base"
)

// Deps carries the shared inputs a module factory may need. Each factory pulls
// only the fields its module requires: every module needs API and Logger, while
// Concurrency bounds detail-fetch fan-out for the modules that do bulk lookups.
type Deps struct {
	API         *client.CrowdStrikeAPISpecification
	Concurrency int
	Logger      *slog.Logger
}

// Factory constructs one module from the shared Deps. Each module exports its
// Factory as a package-level var closing over the module's own wiring (which
// sub-client of Deps.API, whether it uses Concurrency); the generated
// aggregator collects them into the slice passed to Build.
type Factory func(Deps) base.Module

// Build invokes each factory with d and returns the modules in the order the
// factories are given. The aggregator emits them sorted by package name, so the
// result is deterministic without a runtime sort here.
func Build(d Deps, factories []Factory) []base.Module {
	modules := make([]base.Module, 0, len(factories))
	for _, f := range factories {
		modules = append(modules, f(d))
	}
	return modules
}
